INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Silchar', 'overview', 'Overview > Full Name: National Institute of Technology Silchar.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Silchar', 'overview', 'Overview > Location: Silchar-Hailakandi Road, District Cachar, Assam, Pin 788010.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Silchar', 'overview', 'Overview > Languages spoken: Hindi mostly, locals speak Assamese.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Silchar', 'overview', 'Overview > Climate: Humid subtropical. Hot humid summers, intense monsoons from June to September, mild dry winters.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Silchar', 'transport', 'Transport > Bus: ISBT Bus Stand is 11 km from NIT Silchar.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Silchar', 'transport', 'Transport > Airport: Silchar Airport is 25 km from NIT Silchar.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Silchar', 'transport', 'Transport > Railway: Silchar Railway Station is 15 km from NIT Silchar.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Silchar', 'restaurants', 'Restaurants > Nearby: City Dhaba (at NIT gate).');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Silchar', 'restaurants', 'Restaurants > Nearby: Vaishali Dhaba & Restaurant (1.5 km from campus).');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Silchar', 'restaurants', 'Restaurants > Nearby: Promila Restaurant (4.2 km from campus).');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Silchar', 'restaurants', 'Restaurants > Nearby: Madhuban Resort (1 km from campus).');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Silchar', 'nearby_places', 'Nearby Places > Tourist: North East states like Sikkim, Meghalaya, and Tawang are popular trips. No major tourist places in Silchar city itself.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Silchar', 'nearby_places', 'Nearby Places > Shopping: Goldighi Municipal Mall (7.2 km from campus).');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Silchar', 'hostels', 'Hostels > Boys > 1st Year: Aryabhatta Hostel (2 sharing rooms).');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Silchar', 'hostels', 'Hostels > Boys > 1st Year: BH3 (1 sharing / single rooms).');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Silchar', 'hostels', 'Hostels > Boys > 2nd Year: BH8 (3 sharing rooms).');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Silchar', 'hostels', 'Hostels > Boys > 2nd Year: BH4 (3 sharing rooms).');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Silchar', 'hostels', 'Hostels > Boys > 2nd Year: BH1 (3 sharing rooms).');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Silchar', 'hostels', 'Hostels > Boys > 3rd Year: BH9 (blocks 9A, 9B, 9C, 9D) (2 sharing rooms).');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Silchar', 'hostels', 'Hostels > Boys > 3rd Year: BH6 & BH7 (3 sharing rooms).');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Silchar', 'hostels', 'Hostels > Boys > 4th Year: BH9 (single rooms).');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Silchar', 'hostels', 'Hostels > Boys > 4th Year: BH6 & BH7 (single rooms).');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Silchar', 'hostels', 'Hostels > Boys Summary: 1st years get Aryabhatta (2-sharing) or BH3 (single). 2nd years get BH8, BH4, or BH1 (all 3-sharing). 3rd years get BH9 (2-sharing) or BH6/BH7 (3-sharing). 4th years get BH9 or BH6/BH7 (single rooms).');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Silchar', 'mess', 'Mess > Assignment: Every hostel has its own separate mess at NIT Silchar.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Silchar', 'mess', 'Mess > Advance: Rs 21,000 per semester mess advance (adjustable with mess bills).');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Silchar', 'mess', 'Mess > Monday Breakfast: Idli Sambhar Chutney / Bread Butter Jam.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Silchar', 'mess', 'Mess > Monday Lunch: Rice, Dal, Salad (Option 1: Butter Chicken, Option 2: Butter Paneer), Milk/Egg, Curd.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Silchar', 'mess', 'Mess > Monday Snacks: Tea Sandwich.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Silchar', 'mess', 'Mess > Monday Dinner: Rice Dal Salad, Milk Sprouts Banana, Rajma Masala, Rice Kheer.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Silchar', 'mess', 'Mess > Tuesday Breakfast: Sev Poha / Bread Butter Jam.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Silchar', 'mess', 'Mess > Tuesday Lunch: Rice Dal Salad (Option 1: Egg Curry, Option 2: Soyabin Masala), Milk/Egg.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Silchar', 'mess', 'Mess > Tuesday Snacks: Tea Chowmin.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Silchar', 'mess', 'Mess > Tuesday Dinner: Rice Dal Salad, Sprouts Banana, Kadhi Pakoda, Frooti.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Silchar', 'mess', 'Mess > Wednesday Breakfast: Maggi (1.5 pkt) / Bread Butter Jam.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Silchar', 'mess', 'Mess > Wednesday Lunch: Tea, Biscuit Rs 10 (Option 1: Chicken Masala, Option 2: Paneer Masala), Milk/Egg, Curd.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Silchar', 'mess', 'Mess > Wednesday Dinner: Rice Dal Salad, Sprouts Banana, Black Chana Curry, Fruit Custard.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Silchar', 'mess', 'Mess > Thursday Breakfast: Boil Chana Chat Suji Halwa / Bread Butter Jam.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Silchar', 'mess', 'Mess > Thursday Lunch: Rice Dal Salad (Sahi Paneer), Milk.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Silchar', 'mess', 'Mess > Thursday Snacks: Tea Sandwich.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Silchar', 'mess', 'Mess > Thursday Dinner: Rice Dal Salad, Banana, Aloo Tomato Rasawala, Fruit Salad.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Silchar', 'mess', 'Mess > Friday Breakfast: Upma Chutney / Bread Butter Jam.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Silchar', 'mess', 'Mess > Friday Lunch: Rice Dal Salad (Option 1: Chicken Masala, Option 2: Paneer Masala), Milk/Egg.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Silchar', 'mess', 'Mess > Friday Snacks: Tea Bhel.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Silchar', 'mess', 'Mess > Friday Dinner: Rice Dal Salad, Sprouts Banana, Chhole Curry, Rasogolla.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Silchar', 'mess', 'Mess > Saturday Breakfast: Namkin Sewai / Bread Butter Jam.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Silchar', 'mess', 'Mess > Saturday Lunch: Rice Dal Salad (Option 1: Fish Curry, Option 2: Muttar Paneer), Milk/Egg, Curd.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Silchar', 'mess', 'Mess > Saturday Snacks: Tea Chowmin.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Silchar', 'mess', 'Mess > Saturday Dinner: Rice Dal Salad, Sprouts Banana, Rajma Curry, Amul Masti.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Silchar', 'mess', 'Mess > Sunday Breakfast: Cornflakes (15 MRP) / Bread Butter Jam.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Silchar', 'mess', 'Mess > Sunday Lunch: Rice Dal Salad (Option 1: Chicken Curry, Option 2: Paneer Curry), Milk/Egg.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Silchar', 'mess', 'Mess > Sunday Snacks: Tea Bhujia Rs 10.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Silchar', 'mess', 'Mess > Sunday Dinner: Rice Dal Salad, Sprouts Banana, Sev Tomato, Ice Cream/Amul Lassi.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Silchar', 'mess', 'Mess > Notes: Both veg and non-veg options available daily. Chicken served on Monday, Wednesday, Friday, and Sunday. Fish on Saturday. Egg curry on Tuesday. Sweet or dessert served every day.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Silchar', 'mess', 'Mess > Cuisine: North Indian style with both veg and non-veg daily options. Regular items include Rice, Dal, Salad, Sprouts, Banana. Desserts include Rice Kheer, Fruit Custard, Rasogolla, Ice Cream.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Silchar', 'fee_structure', 'Fee Structure > Program: B.Tech 2nd, 4th & 6th Semester (Jan-June 2025).');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Silchar', 'fee_structure', 'Fee Structure > Part I Breakdown: Admission fee Rs 1,000 + Library fee Rs 500 + IT System fee Rs 1,100 + T&P Charges Rs 500 + Transport facility Rs 500 + Medical facility Rs 300 + Examination fee Rs 1,200 + Gymkhana/Sport fee Rs 1,500 + Mediclaim Insurance Rs 270 + Hostel Seat Rent Rs 1,500 + Light and Water charges Rs 1,000 + Cable TV Rs 130 + Mess Establishment Rs 1,500 = Subtotal Rs 11,000.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Silchar', 'fee_structure', 'Fee Structure > SC/ST/PwD Category: Tuition Fee Rs 0, Payable Amount Rs 11,000 per semester.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Silchar', 'fee_structure', 'Fee Structure > Family Income below 1 Lakh: Tuition Fee Rs 0, Payable Amount Rs 11,000 per semester.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Silchar', 'fee_structure', 'Fee Structure > Family Income 1-5 Lakh: Tuition Fee Rs 20,833, Payable Amount Rs 31,833 per semester.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Silchar', 'fee_structure', 'Fee Structure > Family Income above 5 Lakh: Tuition Fee Rs 62,500, Payable Amount Rs 73,500 per semester.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Silchar', 'fee_structure', 'Fee Structure > Part II: BHM Contribution Rs 1,500 + Mess Advance Rs 21,000 (adjustable with mess bills) = Payable Amount Rs 22,500.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Silchar', 'fee_structure', 'Fee Structure > Total per semester (Family income >5L): Part I Rs 73,500 + Part II Rs 22,500 = Rs 96,000.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Silchar', 'fee_structure', 'Fee Structure > 8th Semester: Same structure plus Transcript Fee Rs 1,500 and Convocation Registration Fee Rs 50. Subtotal without tuition: Rs 12,500. SC/ST/PwD: Rs 12,500. Income <1L: Rs 12,500. Income 1-5L: Rs 33,333. Income >5L: Rs 75,000.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Silchar', 'fee_structure', 'Fee Structure > Foreign Students: SAARC countries USD 2,000 per semester. Non-SAARC countries USD 4,000 per semester.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Silchar', 'fee_structure', 'Fee Structure > Payment: DD in favor of Director NIT Silchar, or SBI Collect online portal.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Silchar', 'wifi', 'WiFi > LAN connectivity available in hostel rooms and labs at NIT Silchar.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Silchar', 'wifi', 'WiFi > Mobile network: Jio and Airtel 5G available at NIT Silchar.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Silchar', 'attendance', 'Attendance > 75% attendance is required at NIT Silchar. Enforcement is sir/professor dependent.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Silchar', 'clubs', 'Clubs > Technical/Other: Coding Club, ML Club, E-Cell, Finance Club.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Silchar', 'clubs', 'Clubs > Cultural: Aaveg (dance club).');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Silchar', 'clubs', 'Clubs > Sports Club: Volleyball, Kho-Kho, Kabaddi, Football, Athletics.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Silchar', 'fests', 'Fests > November: Technosis (technical fest).');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Silchar', 'fests', 'Fests > February: Incandescence (cultural fest).');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Silchar', 'laundry', 'Laundry > Washing machines are available in every hostel at NIT Silchar.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Silchar', 'elections', 'Elections > 4th year students nominate candidates at NIT Silchar.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Silchar', 'elections', 'Elections > Positions: GSS (General Secretary Sports), GST (General Secretary Technical), GSC (General Secretary Cultural), VP (Vice President), GS (General Secretary).');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Silchar', 'sports', 'Sports > Available: Volleyball, Football, Chess, Badminton, Basketball, Kho-Kho, Kabaddi, Cricket, Athletics.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Silchar', 'canteen', 'Canteen > Every hostel has its own canteen operating 10 AM to 10 PM at NIT Silchar.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Silchar', 'canteen', 'Canteen > Academic canteen: FPS shops (7 shops) operating 10 AM to 9 PM.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Silchar', 'fines', 'Fines > Late registration fine of Rs 500 per day at NIT Silchar.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Silchar', 'fines', 'Fines > Fine for taking mess plate to room.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Silchar', 'gym', 'Gym > Common gym located in the sports complex at NIT Silchar.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Silchar', 'gym', 'Gym > Free for all students at NIT Silchar.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Silchar', 'health_centre', 'Health Centre > Free dispensary available at NIT Silchar.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Silchar', 'health_centre', 'Health Centre > Located near girls hostel, approximately 800 m from boys hostel.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Silchar', 'language', 'Language > Hindi is mostly spoken at NIT Silchar. Locals speak Assamese.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Silchar', 'climate', 'Climate > Humid subtropical climate. Hot humid summers, intense monsoons from June to September, and mild dry winters.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Silchar', 'academics', 'Academics > 1st Semester (July-Dec 2024): 11 sections (A through K) split into 2 groups.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Silchar', 'academics', 'Academics > Group 1 (Sections A-E) Subjects: PH101 Physics, MA101 Mathematics-I, ME101 Engineering Mechanics, EE101 Basic Electrical Engineering, HS101 Communicative English, CE101 Environmental Science. Labs: PH111 Physics Lab, EE111 Electrical Lab, HS111 Language Lab.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Silchar', 'academics', 'Academics > Group 2 (Sections F-K) Subjects: CH101 Chemistry, MA101 Mathematics-I, CS101 Introduction to Programming, EC101 Basic Electronics, CE102 Environmental Science, ME111 Workshop. Labs: CH111 Chemistry Lab, EC111 Electronics Lab, CS111 Programming Lab, ME111 Workshop.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Silchar', 'academics', 'Academics > Class timings: 8 AM to 5 PM, Monday to Friday, with implicit lunch break.');
